Here is the commit message:
Refactor so Principal is never cached in session with
 cache==false

Here is the root cause:
The bug was caused by the caching of the principal in the session even when caching was disabled, which could lead to incorrect authentication states and security issues. The logic did not properly prevent the principal from being stored in the session when the `cache` flag was set to false, allowing potentially stale or incorrect principal information to persist across sessions.

Here is the patch:
      */
     public void register(Request request, HttpServletResponse response, Principal principal,
             String authType, String username, String password) {

         if (log.isDebugEnabled()) {
             String name = (principal == null) ? "none" : principal.getName();
             log.debug("Authenticated '" + name + "' with type '" + authType + "'");
         }

         // Cache the authentication information in our request
         request.setAuthType(authType);
         request.setUserPrincipal(principal);

         if (sendAuthInfoResponseHeaders
             && Boolean.TRUE.equals(request.getAttribute(Globals.REQUEST_FORWARDED_ATTRIBUTE))) {
             response.setHeader("remote-user", request.getRemoteUser());
             response.setHeader("auth-type", request.getAuthType());
         }

         Session session = request.getSessionInternal(false);

         if (session != null) {
             // If the principal is null then this is a logout. No need to change
             // the session ID. See BZ 59043.
             if (getChangeSessionIdOnAuthentication() && principal != null) {
                 changeSessionID(request, session);
             }
         } else if (alwaysUseSession) {
             session = request.getSessionInternal(true);
         }

         // Cache the authentication information in our session, if any
-        if (cache) {
-            if (session != null) {
+        if (session != null) {
+            if (cache) {
                 session.setAuthType(authType);
                 session.setPrincipal(principal);
+            } else {
                 if (username != null) {
                     session.setNote(Constants.SESS_USERNAME_NOTE, username);
                 } else {
                     session.removeNote(Constants.SESS_USERNAME_NOTE);
                 }
                 if (password != null) {
                     session.setNote(Constants.SESS_PASSWORD_NOTE, password);
                 } else {
                     session.removeNote(Constants.SESS_PASSWORD_NOTE);
                 }
             }
         }

         // Construct a cookie to be returned to the client
         if (sso == null) {
             return;
         }

         // Only create a new SSO entry if the SSO did not already set a note
         // for an existing entry (as it would do with subsequent requests
         // for DIGEST and SSL authenticated contexts)
         String ssoId = (String) request.getNote(Constants.REQ_SSOID_NOTE);
         if (ssoId == null) {
             // Construct a cookie to be returned to the client
             ssoId = sessionIdGenerator.generateSessionId();
             Cookie cookie = new Cookie(Constants.SINGLE_SIGN_ON_COOKIE, ssoId);
             cookie.setMaxAge(-1);
             cookie.setPath("/");

             // Bugzilla 41217
             cookie.setSecure(request.isSecure());

             // Bugzilla 34724
             String ssoDomain = sso.getCookieDomain();
             if (ssoDomain != null) {
                 cookie.setDomain(ssoDomain);
             }

             // Configure httpOnly on SSO cookie using same rules as session
             // cookies
             if (request.getServletContext().getSessionCookieConfig().isHttpOnly() ||
                     request.getContext().getUseHttpOnly()) {
                 cookie.setHttpOnly(true);
             }

             response.addCookie(cookie);

             // Register this principal with our SSO valve
             sso.register(ssoId, principal, authType, username, password);
             request.setNote(Constants.REQ_SSOID_NOTE, ssoId);

         } else {
             if (principal == null) {
                 // Registering a programmatic logout
                 sso.deregister(ssoId);
                 request.removeNote(Constants.REQ_SSOID_NOTE);
                 return;
             } else {
                 // Update the SSO session with the latest authentication data
                 sso.update(ssoId, principal, authType, username, password);
             }
         }

         // Fix for Bug 10040
         // Always associate a session with a new SSO reqistration.
         // SSO entries are only removed from the SSO registry map when
         // associated sessions are destroyed; if a new SSO entry is created
         // above for this request and the user never revisits the context, the
         // SSO entry will never be cleared if we don't associate the session
         if (session == null) {
             session = request.getSessionInternal(true);
         }
         sso.associate(ssoId, session);

     }



